module adder_32bit
(
    input [32:1] A,
    input [32:1] B,
    output [32:1] S,
    output C32
);

wire [15:0] S_lo, S_hi;
wire C16;

// 16-bit CLA for lower 16 bits
assign {C16, S_lo} = A[16:1] + B[16:1];

// 16-bit CLA for upper 16 bits
wire [15:0] P, G, C;
assign P = A[32:17] ^ B[32:17];
assign G = A[32:17] & B[32:17];

wire [15:0] C16_hi;
assign C16_hi[0] = C16;
assign C16_hi[15:1] = C[14:0];
assign {C, S_hi} = P[15:0] + {15'b0, C16_hi[15:1]} + G[15:0];

// Assign output
assign S = {S_hi, S_lo};
assign C32 = C[15];

endmodule
